<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Access Denied</title>
<style>body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;background:#f5f5f5;display:flex;align-items:center;justify-content:center;min-height:100vh;margin:0;}.card{background:white;border-radius:8px;padding:40px;max-width:400px;text-align:center;box-shadow:0 2px 10px rgba(0,0,0,.1);}</style>
</head><body><div class="card"><h2 style="color:#dc3545;">Access Denied</h2><p>{{ $message ?? 'You do not have permission to view this resource.' }}</p><p style="color:#6c757d;font-size:14px;">{{ $reason ?? 'Authentication failed or insufficient permissions.' }}</p><button onclick="window.close()" style="background:#6c757d;color:white;border:none;padding:10px 20px;border-radius:4px;cursor:pointer;">Close</button></div></body></html>
